### New flow

```rust
async fn resolve_chunk_info(
    &self,
    handle: Uuid,
    root_hash: &Blake3Hash,
    merkle_root: &[u8],
    file_size: u64,
) -> Result<(Vec<ResolvedLeaf>, Vec<u64>, bool, HashMap<Blake3Hash, Vec<MerkleChild>>), FsError> {
    // 1. Try cached manifest
    if let Some(cache) = self.cache() {
        if let Ok(Some(manifest)) = cache.get_manifest(&handle).await {
            if manifest.root.as_bytes() == merkle_root {
                // Exact match — reconstruct leaves from manifest, no drill
                let leaves = manifest.chunks.iter().map(|c| ResolvedLeaf { ... }).collect();
                let starts = build_chunk_starts(&leaves, file_size)?;
                // Reconstruct tree_cache from manifest subtrees
                let tree_cache = reconstruct_tree_cache_from_manifest(&manifest);
                return Ok((leaves, starts, true, tree_cache));
            } else {
                // Root hash changed — use old manifest for differential drill
                let resolved = self.resolve_merkle_tree(handle, root_hash, Some(&manifest)).await?;
                let starts = build_chunk_starts(&resolved.leaves, file_size)?;
                return Ok((resolved.leaves, starts, false, resolved.tree_cache));
            }
        }
    }
    // No cached manifest at all — full drill
    let resolved = self.resolve_merkle_tree(handle, root_hash, None).await?;
    let starts = build_chunk_starts(&resolved.leaves, file_size)?;
    Ok((resolved.leaves, starts, false, resolved.tree_cache))
}
```

