Implementation:
const MAX_RETRIES: usize = 3;

async fn fetch_chunk_with_retries(
    &self,
    handle: Uuid,
    leaf: &ResolvedLeaf,
    root_hash: &Blake3Hash,
) -> Result<Bytes, FsError> {
    let mut last_err = FsError::Io;
    for attempt in 0..MAX_RETRIES {
        match self.fetch_chunk_from_network(handle, leaf, root_hash).await {
            Ok(data) => return Ok(data),
            Err(e) => {
                last_err = e;
                if attempt < MAX_RETRIES - 1 {
                    let delay = Duration::from_millis(100 * 2u64.pow(attempt as u32));
                    tracing::warn!(chunk_index = leaf.chunk_index, attempt = attempt + 1, delay_ms = delay.as_millis(), "chunk fetch failed, retrying");
                    tokio::time::sleep(delay).await;
                }
            }
        }
    }
    tracing::error!(chunk_index = leaf.chunk_index, attempts = MAX_RETRIES, "chunk fetch failed after all retries");
    Err(last_err)
}

