```rust
/// Called after transport reconnects. Batch-stats all handles with cached
/// manifests. Invalidates manifests whose root_hash changed.
/// Handles with changed root_hash are added to stale_handles.
pub async fn reconnect_validate_cache(&self) {
    let cache = match self.cache.as_ref() {
        Some(c) => c,
        None => return,  // no cache → nothing to validate
    };

    let handles = match cache.get_all_cached_handles().await {
        Ok(h) => h,
        Err(e) => {
            tracing::warn!("reconnect_validate_cache: failed to list handles: {e}");
            return;
        }
    };

    if handles.is_empty() {
        return;
    }

    let stats = match self.remote.stat_batch(handles.clone()).await {
        Ok(s) => s,
        Err(e) => {
            tracing::warn!("reconnect_validate_cache: stat_batch failed: {e}");
            return;  // can't reach server — skip validation, try again later
        }
    };

    for (handle, result) in handles.into_iter().zip(stats.into_iter()) {
        let fresh_attrs = match result {
            Ok(attrs) => attrs,
            Err(_) => continue,  // handle gone from server? skip
        };

        let manifest = match cache.get_manifest(&handle).await {
            Ok(Some(m)) => m,
            _ => continue,  // manifest disappeared? skip
        };

        if manifest.root.as_bytes() == fresh_attrs.root_hash.as_slice() {
            continue;  // root_hash unchanged → cache valid
        }

        // Root hash changed — invalidate manifest
        tracing::info!(
            "reconnect: handle {handle} root_hash changed, invalidating cache"
        );
        if let Err(e) = cache.remove_manifest(&handle).await {
            tracing::warn!("reconnect: failed to remove manifest for {handle}: {e}");
        }

        // Mark stale — next read() on this handle returns EIO
        self.stale_handles.insert(handle);
    }
}
```

